query SeriesRankingPage($limit: Int!, $offset: Int, $filter: PPVSeriesRankingFilterInput!) {
  ppvSeriesRanking(limit: $limit, offset: $offset, filter: $filter) {
    items {
      id
      rank
      series {
        id
        name
        description
        totalContentsOnSale
        latestContent {
          id
          title
          packageImage {
            mediumUrl
            __typename
          }
          contentType
          ... on PPVContentSummary {
            releaseStatus
            isExclusiveDelivery
            contentType
            pricing {
              sale {
                id
                name
                __typename
              }
              __typename
            }
            maker {
              id
              name
              __typename
            }
            __typename
          }
          __typename
        }
        __typename
      }
      __typename
    }
    __typename
  }
}
